using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Store.Tests;

[TestClass]
public sealed class ShoppingCartTests
{
    private ShoppingCart _sut = null!;

    [TestInitialize]
    public void Setup() => _sut = new ShoppingCart();

    // ─── AddItem ────────────────────────────────────────────────────────

    [TestMethod]
    [DataRow("SKU-1", 1, 9.99, DisplayName = "Single item")]
    [DataRow("SKU-2", 5, 2.50, DisplayName = "Multiple quantity")]
    public void AddItem_ValidInput_AddsToCart(string sku, int qty, double price)
    {
        _sut.AddItem(sku, qty, (decimal)price);

        var total = _sut.CalculateTotal();
        Assert.AreEqual((decimal)(qty * price), total);
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_CombinesQuantity()
    {
        _sut.AddItem("A", 2, 10m);
        _sut.AddItem("A", 3, 10m);

        // 5 × 10 = 50
        Assert.AreEqual(50m, _sut.CalculateTotal());
    }

    [TestMethod]
    [DataRow(null, DisplayName = "Null SKU")]
    [DataRow("", DisplayName = "Empty SKU")]
    [DataRow("   ", DisplayName = "Whitespace SKU")]
    public void AddItem_InvalidSku_ThrowsArgumentException(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(() => _sut.AddItem(sku!, 1, 5m));
    }

    [TestMethod]
    [DataRow(0, DisplayName = "Zero quantity")]
    [DataRow(-1, DisplayName = "Negative quantity")]
    public void AddItem_InvalidQuantity_ThrowsArgumentOutOfRangeException(int qty)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(() => _sut.AddItem("X", qty, 5m));
    }

    [TestMethod]
    public void AddItem_NegativePrice_ThrowsArgumentOutOfRangeException()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(() => _sut.AddItem("X", 1, -1m));
    }

    // ─── RemoveItem ─────────────────────────────────────────────────────

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromCart()
    {
        _sut.AddItem("A", 1, 10m);
        _sut.AddItem("B", 1, 20m);

        _sut.RemoveItem("A");

        Assert.AreEqual(20m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_ThrowsInvalidOperationException()
    {
        Assert.ThrowsException<InvalidOperationException>(() => _sut.RemoveItem("MISSING"));
    }

    [TestMethod]
    [DataRow(null, DisplayName = "Null SKU")]
    [DataRow("", DisplayName = "Empty SKU")]
    public void RemoveItem_InvalidSku_ThrowsArgumentException(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(() => _sut.RemoveItem(sku!));
    }

    // ─── CalculateTotal ─────────────────────────────────────────────────

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_MultipleItems_ReturnsSumOfLineItems()
    {
        _sut.AddItem("A", 2, 5m);   // 10
        _sut.AddItem("B", 1, 7.5m); // 7.5

        Assert.AreEqual(17.5m, _sut.CalculateTotal());
    }

    // ─── ApplyCoupon ────────────────────────────────────────────────────

    [TestMethod]
    [DataRow("SAVE10", 10, DisplayName = "10% off")]
    [DataRow("SAVE20", 20, DisplayName = "20% off")]
    [DataRow("HALF", 50, DisplayName = "50% off")]
    public void ApplyCoupon_ValidCode_AppliesDiscount(string code, int discountPct)
    {
        _sut.AddItem("X", 1, 100m);
        _sut.ApplyCoupon(code);

        var expected = 100m - (100m * discountPct / 100m);
        Assert.AreEqual(expected, _sut.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_CaseInsensitive_AppliesDiscount()
    {
        _sut.AddItem("X", 1, 100m);
        _sut.ApplyCoupon("save10");

        Assert.AreEqual(90m, _sut.CalculateTotal());
    }

    [TestMethod]
    [DataRow("INVALID", DisplayName = "Unknown code")]
    [DataRow("EXPIRED", DisplayName = "Expired code")]
    public void ApplyCoupon_InvalidCode_ThrowsArgumentException(string code)
    {
        Assert.ThrowsException<ArgumentException>(() => _sut.ApplyCoupon(code));
    }

    [TestMethod]
    [DataRow(null, DisplayName = "Null code")]
    [DataRow("", DisplayName = "Empty code")]
    public void ApplyCoupon_NullOrEmpty_ThrowsArgumentException(string? code)
    {
        Assert.ThrowsException<ArgumentException>(() => _sut.ApplyCoupon(code!));
    }

    [TestMethod]
    public void ApplyCoupon_AppliedAfterAddingItems_DiscountsFullTotal()
    {
        _sut.AddItem("A", 2, 25m); // 50
        _sut.AddItem("B", 1, 50m); // 50
        _sut.ApplyCoupon("SAVE20");

        // Total 100 − 20% = 80
        Assert.AreEqual(80m, _sut.CalculateTotal());
    }
}

